mapper.insert:
INSERT INTO ledger_records (
    record_id, inspection_date, content, docx_path, sync_version
) VALUES (
    #{recordId}, #{inspectionDate}, #{content}, #{docxPath}, #{syncVersion}
)

mapper.select:
SELECT *
FROM ledger_records
WHERE sync_version > #{syncVersion}
ORDER BY sync_version ASC
LIMIT #{limit}
